   bNouvelEtat = bReadPin(2,3);
  if (bNouvelEtat != bAncienEtat){
    bAncienEtat = bNouvelEtat;
    if(bNouvelEtat == 1)
    {
      CompteurSw2 = 0;
      while (CompteurSw2 < 80000)
      {
        CompteurSw2++;
      }
      ucPort1 = ucPort1 >> 1;
      if (ucPort1 == 0){
        ucPort1 = 0x80;
      }
    }
    }
    vWritePort(ucPort1,1);
}

void Chrono(){
  if (ucFlagTM2 ==1){
    ucFlagTM2 = 0;
    ucDSecond++;
    if(ucDSecond > 9){
      ucDSecond = 0;
      ucSecond++;
      if(ucSecond > 15){
        ucSecond = 0;
      }
    }
  }
  ucResult = (ucSecond << 4) | ucDSecond;
  vWritePort(ucResult, 1);
}

void Button(){
      bNouvelEtat = bReadPin(2,3);
    if (bNouvelEtat != bAncienEtat){
    bAncienEtat = bNouvelEtat;
    if(bNouvelEtat == 1)
    {
      CompteurSw2 = 0;
      while (CompteurSw2 < 80000)
      {
        CompteurSw2++;
      }
      running = !running;
      if(running){
        HAL_TIM_Base_Start_IT(&htim2);
      }else{
        HAL_TIM_Base_Stop_IT(&htim2);
      }
    }
    }

bNouvelEtat2 = bReadPin(2,4);
    if (bNouvelEtat2 != bAncienEtat2){
    bAncienEtat2 = bNouvelEtat2;
    if(bNouvelEtat2 == 1)
    {
      CompteurSw2_2 = 0;
      while (CompteurSw2_2 < 80000)
      {
        CompteurSw2_2++;
      }
        __HAL_TIM_SET_COUNTER(&htim2, 0);
        ucDSecond = 0;
        ucSecond = 0;
    }
    }
}

