void Dimmer(){
    ne = ucReadPort(2);
    if(ne != ucPort2){    //Detecte si il y a un changement sur le port 2
      ucPort2 = ne;
      if(ne != 0xFF){     //Different de FF si un bouton est pese
        CompteurSw2 = 0;
      while(CompteurSw2 < 80000){       //Anti rebond
        CompteurSw2++;
      }
     switch (ucPort2)
      {
      case 0xEF:                        //SW4
        iIntensite -= 5;
        if(iIntensite <= 00){
          iIntensite = 0;
        }
        break;
      case 0xF7:
        iIntensite = 50;                //SW3
        break;

      case 0xFB:                        //SW2
        iIntensite += 5;
        if(iIntensite >= 100){
          iIntensite = 100;
        }
        break;
      }
      RefreshScreen();                 //Met a jour l`ecran
    }
    }

    if (ucFlagTM2 == 1){          //Debordement timer
      ucFlagTM2 = 0;
      compteur++;
      int test = (int)((float)iIntensite/100 * 20);
      if (compteur > 20){
        compteur = 0;
      }
      if(compteur < test){
        ucPort1 = 0xFF;
      } else {
        ucPort1 = 0;
      }
    }

    vWritePort(ucPort1,1);
}
