void ScreenUpdate()
{
	static uint8_t digit = 0;

	// Digit scanning
	// Digit pins is connected to the base of pnp transistor
	GPIO_DIG->ODR = ~(1 << (digit + 8)) & 0x0F00;
	// The LED 7 segment is common anode
	GPIO_SEG->ODR = (~font[buffer[digit]] << 8) & 0xFF00;

	digit++;
	if (digit > (SS_DIGIT-1))
	{
		digit = 0;
	}
}
