void Heart(){
  static const UC pattern[9] = {0xFF,0xFE,0xFC,0xF8,0xF0,0xE0,0xC0,0x80,0x00};
  static char index = 0;
  static bool up = true;

  if(ucFlagTM2 == 1){
    ucFlagTM2 = 0;
    if (index > 9){
      up = false;
      index = 8;
    }
    if (index == 0){
      up = true;
      index = 0;
    }
    if(up){
      index++;
    }else{
      index--;
    }
  }

  ucPort1 = pattern[index];
  vWritePort(~ucPort1,1);
}
